# Calculator type definitions and base classes

class CalcError:
    message: str

    def __init__(self, msg: str):
        self.message = msg

    def __str__(self) -> str:
        return f"CalcError: {self.message}"

@abstract
class Operation:
    name: str

    @abstract
    def execute(self, x: float, y: float) -> float:
        ...

    def describe(self) -> str:
        return f"Operation: {self.name}"

class Addition(Operation):
    def __init__(self):
        self.name = "Addition"

    @override
    def execute(self, x: float, y: float) -> float:
        return x + y

class Multiplication(Operation):
    def __init__(self):
        self.name = "Multiplication"

    @override
    def execute(self, x: float, y: float) -> float:
        return x * y

def format_result(value: float) -> str:
    return f"Result: {value:.2f}"

