# Calculation history tracking
# Depends on: calc_types

from calc_types import CalcError

class HistoryEntry:
    operation: str
    operand1: float
    operand2: float
    result: float

    def __init__(self, op: str, a: float, b: float, res: float):
        self.operation = op
        self.operand1 = a
        self.operand2 = b
        self.result = res

class CalculatorHistory:
    entries: list[HistoryEntry]

    def __init__(self):
        self.entries = []

    def record(self, op: str, a: float, b: float, res: float) -> None:
        entry: HistoryEntry = HistoryEntry(op, a, b, res)
        self.entries.append(entry)

    def get_last(self) -> HistoryEntry:
        if len(self.entries) == 0:
            raise CalcError("No history entries")
        return self.entries[len(self.entries) - 1]

    def get_count(self) -> int:
        return len(self.entries)

    def print_summary(self) -> None:
        print(f"Total calculations: {self.get_count()}")

