# Additional calculator operations
# Depends on: calc_types

from calc_types import Operation, CalcError

@final
class Division(Operation):
    def __init__(self):
        self.name = "Division"

    @override
    def execute(self, x: float, y: float) -> float:
        if y == 0.0:
            raise CalcError("Division by zero")
        return x / y

@final
class Subtraction(Operation):
    def __init__(self):
        self.name = "Subtraction"

    @override
    def execute(self, x: float, y: float) -> float:
        return x - y
